import{_ as o,o as e,c as s,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"33A. 24. 7. Rostering","description":"","frontmatter":{"title":"33A. 24. 7. Rostering","eba":"Doctors in Training 2022-2026","topics":["hours","shift-work","rosters"]},"headers":[],"relativePath":"ebas/doctors-in-training/hours-of-work/33A-24-7-rostering.md","filePath":"ebas/doctors-in-training/hours-of-work/33A-24-7-rostering.md"}'),n={name:"ebas/doctors-in-training/hours-of-work/33A-24-7-rostering.md"};function i(a,t,g,l,p,h){return e(),s("div",null,[...t[0]||(t[0]=[r('<h1 id="_33a-24-7-rostering" tabindex="-1">33A. 24. 7. Rostering <a class="header-anchor" href="#_33a-24-7-rostering" aria-label="Permalink to &quot;33A. 24. 7. Rostering&quot;">​</a></h1><p><strong>33A.1</strong> Where a Health Service rosters Doctors on a 24/7 basis in any part of its organisation, the rosters will include overlap between the shifts to allow for handover.</p><p><strong>33A.2</strong> Examples of a 24/7 roster include but are not limited to:</p><p><strong>(a)</strong> Three shifts across each twenty-four hour period as follows:</p><p><strong>(i)</strong> a &quot;morning&quot; or &quot;AM&quot; shift;</p><p><strong>(ii)</strong> an &quot;afternoon&quot; or &quot;PM&quot; shift; or</p><p><strong>(iii)</strong> a &quot;night duty&quot; or &quot;ND&quot; shift,</p><p>with these shifts typically not exceeding 10 hours each.</p><p><strong>(b)</strong> Two shifts across each twenty-four hour period as follows:</p><p><strong>(i)</strong> a &quot;morning&quot; or &quot;AM&quot; shift; or</p><p><strong>(ii)</strong> an &quot;afternoon&quot; or &quot;PM&quot; shift,</p><p>with these shifts typically being at least 12 hours (excluding meal break) but no greater than 14 hours each.</p><p><strong>33A.3</strong> Notwithstanding the typical shift lengths described at subclause 33A.2 shifts will not exceed the limit set out at subclause 33.3.</p><p><strong>33A.4</strong> Nothing in this term prevents other shift configurations (such as &quot;saddle&quot; shifts).</p><p><strong>33A.5</strong> Nothing in this term prevents rosters with an &quot;accrued&quot; time model (such as &quot;Accrued Day Off&quot;) through <a href="/eba/ebas/doctors-in-training/consultation-disputes/16-individual-flexibility-arrangements.html">clause 16</a> (Individual Flexibility Arrangement).</p><p><strong>33A.6</strong> Existing 24/7 rosters</p><p>Where a Health Service currently has a 24/7 roster, the current roster will be:</p><p><strong>(a)</strong> posted as required by <a href="/eba/ebas/doctors-in-training/hours-of-work/35-rosters.html">clause 35</a> of this Agreement; and</p><p><strong>(b)</strong> available for discussion at the WIC.</p><p><strong>33A.7</strong> New 24/7 rosters</p><p>It is acknowledged that a Health Service may wish to transition to a permanent 24/7 rostering in a part of its organisation for reasons including but not limited to the meeting of service needs having regard for activity levels. Where this is proposed, the Health Service shall:</p><p><strong>(a)</strong> consult as required by <a href="/eba/ebas/doctors-in-training/consultation-disputes/10-consultation.html">clause 10</a> or 10A (depending on the circumstances);</p><p><strong>(b)</strong> provide a copy of the proposed roster to the Association; and</p><p><strong>(c)</strong> provide a copy of the roster, following consultation, to the Association.</p><p><strong>33A.8</strong> Reform to Meet Service Demand - Engagement</p><p><strong>(a)</strong> It is acknowledged that as a result of a range of factors including increases in service demand, more service areas may seek to establish 24/7 rostering over time. To support this, it is also acknowledged that this will require:</p><p><strong>(i)</strong> Additional EFT; and</p><p><strong>(ii)</strong> Consultation with Health Services, Doctors, Specialist Medical Colleges and PMCV with respect to matters including training and accreditation requirements.</p><p><strong>(b)</strong> The BPEC will develop a suitable consultation process.</p><p>Plain language terms: 24/7, continuous roster.</p>',30)])])}const d=o(n,[["render",i]]);export{u as __pageData,d as default};
